// ── Language Manager ─────────────────────────────────────────

export class LanguageManager {
  private currentLang: LangCode = 'en';
  private listeners: Set<(lang: LangCode) => void> = new Set();
  private detected = false;

  async detectLanguage(): Promise<LangCode> {
    // Check localStorage first
    const stored = typeof localStorage !== 'undefined'
      ? localStorage.getItem('ghl-vc-lang') as LangCode
      : null;
    if (stored && translations[stored]) {
      this.currentLang = stored;
      this.detected = true;
      return stored;
    }

    // Try IP geolocation
    try {
      const resp = await fetch('https://ipapi.co/json/', { signal: AbortSignal.timeout(3000) });
      if (resp.ok) {
        const data = await resp.json();
        const lang = detectLanguageFromRegion(data.region || '', data.country_code || '');
        this.currentLang = lang;
        this.detected = true;
        this.persist();
        return lang;
      }
    } catch { /* fall through */ }

    // Browser language fallback
    const browserLang = this.detectFromBrowser();
    this.currentLang = browserLang;
    this.detected = true;
    this.persist();
    return browserLang;
  }

  detectFromBrowser(): LangCode {
    if (typeof navigator === 'undefined') return 'en';
    const navLang = navigator.language?.toLowerCase() || '';
    const prefix = navLang.split('-')[0];
    const match = LANGUAGES.find(l => l.code === prefix);
    return match ? match.code : 'en';
  }

  getTranslations(lang?: LangCode): Translations {
    return translations[lang || this.currentLang] || translations.en;
  }

  getTimeGreeting(lang?: LangCode, hour?: number): string {
    const h = hour ?? new Date().getHours();
    const t = this.getTranslations(lang);
    if (h >= 5 && h < 12) return t.greeting_morning;
    if (h >= 12 && h < 17) return t.greeting_afternoon;
    if (h >= 17 && h < 21) return t.greeting_evening;
    return t.greeting_night;
  }

  translate(key: keyof Translations, lang?: LangCode): string {
    const t = this.getTranslations(lang);
    const val = t[key];
    return typeof val === 'string' ? val : '';
  }

  isRTL(lang?: LangCode): boolean {
    const code = lang || this.currentLang;
    return LANGUAGES.find(l => l.code === code)?.rtl ?? false;
  }

  getVoiceLang(lang?: LangCode): string {
    const code = lang || this.currentLang;
    return LANGUAGES.find(l => l.code === code)?.voiceLang || 'en-IN';
  }

  getLanguageInfo(lang?: LangCode): LanguageOption | undefined {
    return LANGUAGES.find(l => l.code === (lang || this.currentLang));
  }

  getCurrentLanguage(): LangCode {
    return this.currentLang;
  }

  setLanguage(lang: LangCode): void {
    if (this.currentLang === lang) return;
    this.currentLang = lang;
    this.persist();
    this.listeners.forEach(fn => fn(lang));
  }

  isDetected(): boolean {
    return this.detected;
  }

  on(event: 'languageChanged', handler: (lang: LangCode) => void): void {
    this.listeners.add(handler);
  }

  off(handler: (lang: LangCode) => void): void {
    this.listeners.delete(handler);
  }

  private persist(): void {
    if (typeof localStorage !== 'undefined') {
      localStorage.setItem('ghl-vc-lang', this.currentLang);
    }
  }
}

// ── Helpers ──────────────────────────────────────────────────

export function detectLanguageFromRegion(region: string, country: string): LangCode {
  const r = region?.toLowerCase() || '';
  const c = country?.toLowerCase() || '';
  if (c === 'in') {
    if (['tamil nadu', 'tn', 'puducherry', 'py'].some(s => r.includes(s))) return 'ta';
    if (['andhra pradesh', 'ap', 'telangana', 'ts'].some(s => r.includes(s))) return 'te';
    if (['karnataka', 'ka'].some(s => r.includes(s))) return 'kn';
    if (['kerala', 'kl', 'lakshadweep', 'ld'].some(s => r.includes(s))) return 'ml';
    return 'hi';
  }
  if (['es', 'mx', 'ar', 'co', 'cl', 'pe', 'ec', 've'].includes(c)) return 'es';
  if (['fr', 'be', 'ch', 'ca', 'sn', 'ci', 'cm'].includes(c)) return 'fr';
  if (['de', 'at'].includes(c)) return 'de';
  if (['sa', 'ae', 'qa', 'kw', 'bh', 'om', 'eg', 'jo', 'lb', 'iq'].includes(c)) return 'ar';
  if (['cn', 'tw', 'hk', 'sg'].includes(c)) return 'zh';
  if (c === 'jp') return 'ja';
  if (['br', 'pt', 'ao', 'mz'].includes(c)) return 'pt';
  if (['ru', 'by', 'kz', 'uz', 'kg'].includes(c)) return 'ru';
  return 'en';
}
